def add_distance_selling(locale, trans):
    filepath = os.path.join(BASE, f"{locale}.json")
    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()

    data = json.loads(content)
    terms = data.get("Terms", {})

    # Rebuild Terms with distanceSelling inserted after subscriptions
    new_terms = {}
    for k, v in terms.items():
        new_terms[k] = v
        if k == "subscriptions":
            new_terms["distanceSelling"] = trans

    data["Terms"] = new_terms

    with open(filepath, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
        f.write('\n')


if __name__ == "__main__":
    for locale, trans in TRANSLATIONS.items():
        add_distance_selling(locale, trans)
        # Verify
        with open(os.path.join(BASE, f"{locale}.json"), 'r', encoding='utf-8') as f:
            d = json.load(f)
        ok = "distanceSelling" in d.get("Terms", {})
        print(f"{locale}: {'OK' if ok else 'MISSING'}")

    print("Done.")
